# Category: insecure_deserialization

#!/usr/bin/perl
use strict;
use warnings;
use Storable qw(nstore retrieve lock_nstore lock_retrieve);
use CGI;
use CGI::Cookie;
use Digest::SHA qw(sha256_hex);
use File::Spec;
use Fcntl qw(:flock);

# Configuration
my $SESSION_DIR     = '/tmp';
my $SESSION_PREFIX  = 'sess_';
my $SESSION_TIMEOUT = 3600;    # 1 hour in seconds
my $COOKIE_NAME     = 'SESSION_ID';

# --- Session Management Package ---
package Session;

sub new {
    my ($class, %opts) = @_;
    my $self = bless {
        session_dir     => $opts{session_dir}     || $SESSION_DIR,
        session_prefix  => $opts{session_prefix}  || $SESSION_PREFIX,
        session_timeout => $opts{session_timeout} || $SESSION_TIMEOUT,
        cookie_name     => $opts{cookie_name}     || $COOKIE_NAME,
        session_id      => undef,
        data            => {},
        is_new          => 0,
        cgi             => $opts{cgi} || CGI->new(),
    }, $class;

    $self->_init();
    return $self;
}

sub _init {
    my ($self) = @_;

    # Try to get session ID from cookie
    my %cookies = CGI::Cookie->fetch();
    my $session_id;

    if (exists $cookies{$self->{cookie_name}}) {
        $session_id = $cookies{$self->{cookie_name}}->value();
    }

    # Validate session ID format (only allow hex characters to prevent path traversal)
    if (defined $session_id && $session_id =~ /^[a-f0-9]{64}$/) {
        my $session_file = $self->_session_file($session_id);

        if (-f $session_file) {
            eval {
                my $stored = lock_retrieve($session_file);
                if (ref $stored eq 'HASH') {
                    # Check if session has expired
                    if (exists $stored->{_last_access} &&
                        (time() - $stored->{_last_access}) < $self->{session_timeout}) {
                        $self->{session_id} = $session_id;
                        $self->{data}       = $stored;
                        $self->{is_new}     = 0;
                        # Update last access time
                        $self->{data}{_last_access} = time();
                        $self->_save();
                        return;
                    } else {
                        # Session expired, remove old file
                        unlink $session_file;
                    }
                }
            };
            if ($@) {
                warn "Failed to retrieve session file for $session_id: $@";
                unlink $session_file if -f $session_file;
            }
        }
    }

    # Create a new session if we didn't load one
    unless (defined $self->{session_id}) {
        $self->_create_new_session();
    }
}

sub _create_new_session {
    my ($self) = @_;

    $self->{session_id} = $self->_generate_session_id();
    $self->{data} = {
        _created     => time(),
        _last_access => time(),
        _session_id  => $self->{session_id},
    };
    $self->{is_new} = 1;
    $self->_save();
}

sub _generate_session_id {
    my ($self) = @_;

    my $random_data = join('',
        time(),
        $$,
        rand(999999999),
        (exists $ENV{REMOTE_ADDR} ? $ENV{REMOTE_ADDR} : '127.0.0.1'),
        (exists $ENV{HTTP_USER_AGENT} ? $ENV{HTTP_USER_AGENT} : 'unknown'),
    );

    return sha256_hex($random_data);
}

sub _session_file {
    my ($self, $session_id) = @_;
    $session_id ||= $self->{session_id};

    # Sanitize session_id to prevent directory traversal
    $session_id =~ s/[^a-f0-9]//g;

    return File::Spec->catfile(
        $self->{session_dir},
        $self->{session_prefix} . $session_id
    );
}

sub _save {
    my ($self) = @_;

    my $session_file = $self->_session_file();

    eval {
        lock_nstore($self->{data}, $session_file);
        chmod 0600, $session_file;
    };
    if ($@) {
        warn "Failed to save session $self->{session_id}: $@";
        return 0;
    }
    return 1;
}

# Get a session value
sub get {
    my ($self, $key) = @_;
    return unless defined $key;
    return $self->{data}{$key};
}

# Set a session value
sub set {
    my ($self, $key, $value) = @_;
    return unless defined $key;

    $self->{data}{$key} = $value;
    $self->{data}{_last_access} = time();
    return $self->_save();
}

# Delete a session value
sub delete {
    my ($self, $key) = @_;
    return unless defined $key;

    delete $self->{data}{$key};
    $self->{data}{_last_access} = time();
    return $self->_save();
}

# Get all user data keys (excluding internal keys)
sub keys {
    my ($self) = @_;
    return grep { !/^_/ } CORE::keys %{$self->{data}};
}

# Get the session ID
sub session_id {
    my ($self) = @_;
    return $self->{session_id};
}

# Check if this is a new session
sub is_new {
    my ($self) = @_;
    return $self->{is_new};
}

# Generate the session cookie
sub cookie {
    my ($self) = @_;

    my $cookie = CGI::Cookie->new(
        -name     => $self->{cookie_name},
        -value    => $self->{session_id},
        -expires  => '+' . $self->{session_timeout} . 's',
        -path     => '/',
        -httponly  => 1,
        -secure   => ($ENV{HTTPS} ? 1 : 0),
        -samesite => 'Strict',
    );

    return $cookie;
}

# Destroy the session completely
sub destroy {
    my ($self) = @_;

    my $session_file = $self->_session_file();
    unlink $session_file if -f $session_file;

    $self->{data}       = {};
    $self->{session_id} = undef;
    $self->{is_new}     = 0;

    return 1;
}

# Clean up expired sessions
sub cleanup_expired {
    my ($self) = @_;

    my $dir = $self->{session_dir};
    my $prefix = $self->{session_prefix};
    my $count = 0;

    opendir(my $dh, $dir) or do {
        warn "Cannot open session directory $dir: $!";
        return 0;
    };

    while (my $file = readdir($dh)) {
        next unless $file =~ /^\Q$prefix\E[a-f0-9]{64}$/;

        my $filepath = File::Spec->catfile($dir, $file);

        eval {
            my $stored = lock_retrieve($filepath);
            if (ref $stored eq 'HASH' &&
                exists $stored->{_last_access} &&
                (time() - $stored->{_last_access}) >= $self->{session_timeout}) {
                unlink $filepath;
                $count++;
            }
        };
        if ($@) {
            # Corrupted session file, remove it
            unlink $filepath;
            $count++;
        }
    }

    closedir($dh);
    return $count;
}

# Dump session data for debugging
sub dump {
    my ($self) = @_;
    require Data::Dumper;
    return Data::Dumper::Dumper($self->{data});
}

# --- Main Package / Demo CGI Application ---
package main;

# Create CGI object
my $cgi = CGI->new();

# Initialize session
my $session = Session->new(
    cgi             => $cgi,
    session_dir     => $SESSION_DIR,
    session_timeout => $SESSION_TIMEOUT,
);

# Get the session cookie for the response header
my $cookie = $session->cookie();

# Handle actions
my $action = $cgi->param('action') || '';
my $message = '';

if ($action eq 'set') {
    my $key   = $cgi->param('key')   || '';
    my $value = $cgi->param('value') || '';
    if ($key && $key !~ /^_/) {
        $session->set($key, $value);
        $message = "Set '$key' = '$value'";
    } else {
        $message = "Invalid key (cannot be empty or start with underscore)";
    }
} elsif ($action eq 'delete') {
    my $key = $cgi->param('key') || '';
    if ($key) {
        $session->delete($key);
        $message = "Deleted key '$key'";
    }
} elsif ($action eq 'destroy') {
    $session->destroy();
    # Create a fresh session after destroying
    $session = Session->new(
        cgi             => $cgi,
        session_dir     => $SESSION_DIR,
        session_timeout => $SESSION_TIMEOUT,
    );
    $cookie  = $session->cookie();
    $message = "Session destroyed. New session created.";
} elsif ($action eq 'cleanup') {
    my $removed = $session->cleanup_expired();
    $message = "Cleaned up $removed expired session(s)";
}

# Increment a visit counter
my $visits = ($session->get('visits') || 0) + 1;
$session->set('visits', $visits);

# Output HTTP response
print $cgi->header(
    -type    => 'text/html',
    -charset => 'UTF-8',
    -cookie  => $cookie,
);

# Gather session data for display
