        . "<input type='hidden' name='action' value='delete'>"
        . "<input type='hidden' name='key' value='$key'>"
        . "<button type='submit'>Delete</button>"
        . "</form></td></tr>\n";
}

my $session_id_display = CGI::escapeHTML($session->session_id() || 'N/A');
my $is_new_display     = $session->is_new() ? 'Yes' : 'No';
my $message_html       = $message ? "<div class='message'>" . CGI::escapeHTML($message) . "</div>" : '';

